+
+    /// Create a new ConfigErrorDisplay with error code.
+    #[must_use]
+    fn new(error_code: ErrorCode) -> Self {
+        Self {
+            error_code,
+            location: None,
+            snippet: None,
+            type_mismatch: None,
+            search_paths: None,
+            env_var_name: None,
+            env_var_value: None,
+            profile_name: None,
+            worker_id: None,
+            ssh_key_path: None,
+            socket_path: None,
+            permission_mode: None,
