+
+    /// Serialize to JSON string.
+    pub fn to_json(&self) -> serde_json::Result<String> {
+        serde_json::to_string_pretty(self)
+    }
+
+    /// Serialize to compact JSON string.
+    pub fn to_json_compact(&self) -> serde_json::Result<String> {
